module fsm_risk (
    input clk,
    input rst,
    input start,
    output reg done
);
    reg [1:0] state, next_state;
    always @(posedge clk) begin
        if (rst) state <= 2'b00;
        else state <= next_state;
    end

    always @(*) begin
        case(state)
            2'b00: if (start) next_state = 2'b01;
            2'b01: next_state = 2'b10;
            2'b10: begin 
                done = 1; 
                next_state = 2'b00;
            end
        endcase
    end
endmodule

output:
### Synthesis Risk (Linter Escape):
This is an incomplete combinational logic block. In the lways @(*) block, 
ext_state and done are not assigned in all possible branches. For instance, done is only assigned in state 2'b10. Furthermore, 
ext_state is missing a default assignment. The synthesizer will infer transparent latches to hold the values of 
ext_state and done, which breaks the timing paths and makes STA (Static Timing Analysis) unreliable.

### Optimized Verilog:
Always assign default values at the top of a combinational block or explicitly cover all cases to prevent latch inference.

`erilog
module fsm_safe (
    input clk,
    input rst,
    input start,
    output reg done
);
    reg [1:0] state, next_state;
    always @(posedge clk) begin
        if (rst) state <= 2'b00;
        else state <= next_state;
    end

    always @(*) begin
        // Default assignments prevent latches
        next_state = state;
        done = 0;

        case(state)
            2'b00: if (start) next_state = 2'b01;
            2'b01: next_state = 2'b10;
            2'b10: begin 
                done = 1;
                next_state = 2'b00;
            end
            default: next_state = 2'b00;
        endcase
    end
endmodule
`

