    wire [7:0] dut_out;

    initial clk = 0;
    always #5 clk = ~clk;

    // Using SystemVerilog Clocking Block
    clocking cb @(posedge clk);
        default input #1step output #1;
        input dut_out;
    endclocking

    always @(cb) begin
        if (cb.dut_out == 8'hFF) begin
            ("Max value reached reliably");
        end
    end
endmodule
